    protected override void OnLoad(EventArgs e)
    {
        base.OnLoad(e);

        // .NET 9 breaking change: StatusStrip default renderer switched from
        // Professional to System. Explicitly set Professional to preserve .NET 8 look.
        _statusStrip = new StatusStrip();
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        Controls.Add(_statusStrip);
    }

    // .NET 9 breaking change: DropDownControl(null) now throws ArgumentNullException.
    // Always guard against null before calling.
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        if (control is not null)
