            editorService.DropDownControl(control);
        }
    }

    // .NET 9 breaking change: DllImport-based COM interop requires opting in to the
    // built-in COM interop support via the runtime config switch.
    [DllImport("user32.dll", SetLastError = true)]
    private static extern int GetSystemMetrics(int nIndex);

    public int GetScreenWidth() => GetSystemMetrics(0);
}

